const jobData = $('Fetch Job and Candidates').first().json;

let gabarito = jobData.gabarito;

if (!gabarito) {
  const raw = $('Prompt 0 — Extract Job Template').first().json.output[0].content[0].text;
  gabarito = JSON.parse(raw);
}

const candidates = typeof jobData.candidates === 'string'
  ? JSON.parse(jobData.candidates)
  : jobData.candidates;

return candidates.map(c => ({
  json: {
    job_id:         jobData.job_id,
    job_title:      jobData.title,
    gabarito:       gabarito,
    candidate_id:   c.id,
    candidate_name: c.name,
    cv_text:        c.cv_text
  }
}));

