const candidate = $('Loop Candidates').item.json;

const score_data = JSON.parse($('Prompt 1 — Score').item.json.output[0].content[0].text);
const gaps_data  = JSON.parse($('Prompt 2 — Gaps').item.json.output[0].content[0].text);
const pergs_data = JSON.parse($('Prompt 3 — Interview Questions').item.json.output[0].content[0].text);

return [{
  json: {
    candidate_id:          candidate.candidate_id,
    job_id:                candidate.job_id,
    score:                 score_data.score,
    nivel_aderencia:       score_data.adherence_level,
    justificativa_score:   score_data.justification,
    score_criterios:       score_data.criteria_scores,
    pontos_fortes:         gaps_data.strengths,
    gaps_criticos:         gaps_data.critical_gaps,
    gaps_secundarios:      gaps_data.secondary_gaps,
    perguntas_entrevista:  pergs_data.interview_questions
  }
}];

const raw  = $('Prompt 4 — Executive Summary').item.json.output[0].content[0].text;
const data = JSON.parse(raw);
const job_id = $('Build Analysis Payload').item.json.job_id;

return [{
  json: {
    job_id:           job_id,
    total_analisados: data.total_analyzed,
    recomendados:     data.recommended,
    destaque:         data.destaque,
    gap_comum:        data.gap_comum,
    resumo:           data.resumo
  }
}];
